const projects = $input.first().json.list || $input.first().json || [];
if (!Array.isArray(projects) || projects.length === 0) {
  throw new Error('Нет активных проектов для обновления СЯ');
}
return projects.map(p => ({ json: {
  niche: p.niche, city: p.city, project_id: p.project_id || p.Id,
  seed_keywords: p.seed_keywords ? JSON.parse(p.seed_keywords) : [],
  max_keywords: p.max_keywords || 500,
  source: 'cron'
}}));

const body = $input.first().json.body || $input.first().json;
const { niche, city, project_id, seed_keywords, max_keywords, source } = body;

if (!niche || typeof niche !== 'string' || niche.length < 2 || niche.length > 200)
  throw new Error('Поле "niche" обязательно (2-200 символов)');
if (!city || typeof city !== 'string')
  throw new Error('Поле "city" обязательно');
if (!project_id)
  throw new Error('Поле "project_id" обязательно');

// Sanitize inputs
const sanitize = (s) => s.replace(/[<>{}\\"'`;]/g, '').trim();
const cleanNiche = sanitize(niche);
const cleanCity = sanitize(city);

let seeds = Array.isArray(seed_keywords) && seed_keywords.length > 0
  ? seed_keywords.map(s => sanitize(String(s))).filter(Boolean)
  : [
      cleanNiche + ' ' + cleanCity, cleanNiche, cleanNiche + ' цена',
      cleanNiche + ' стоимость', cleanNiche + ' отзывы', cleanNiche + ' рядом',
      cleanNiche + ' недорого', cleanNiche + ' заказать', cleanNiche + ' услуги',
      cleanNiche + ' рейтинг', cleanNiche + ' лучший ' + cleanCity,
      cleanNiche + ' адреса ' + cleanCity
    ];

const regionMap = {
  'Москва': 213, 'Санкт-Петербург': 2, 'Новосибирск': 65,
  'Екатеринбург': 54, 'Казань': 43, 'Нижний Новгород': 47,
  'Краснодар': 35, 'Челябинск': 56, 'Самара': 51, 'Ростов-на-Дону': 39,
  'Уфа': 172, 'Красноярск': 62, 'Пермь': 50, 'Воронеж': 36, 'Волгоград': 38,
  'Тюмень': 55, 'Омск': 66, 'Саратов': 194, 'Тольятти': 240, 'Барнаул': 197
};

const regionId = regionMap[cleanCity] || 213;
const startTime = Date.now();

return [{ json: {
  niche: cleanNiche, city: cleanCity, project_id: String(project_id),
  seeds, max_keywords: Math.min(Math.max(parseInt(max_keywords) || 500, 50), 2000),
  region_id: regionId,
  embed_query: cleanNiche + ' ' + cleanCity + ' семантическое ядро SEO кластеризация',
  source: source || 'webhook',
  start_time: startTime,
  workflow_version: 'v4.0_pro',
  attempt: body.attempt || 1
}}];

const data = $('Validate & Sanitize Input').first().json;
return [{ json: {
  ...data,
  wordstat_payload: {
    phrases: data.seeds,
    regions: [data.region_id],
    numPhrases: 100
  }
}}];

let ragResults = [];
try { ragResults = $('RAG Search Niche Analyses').first().json.result || []; } catch(e) {}

let context = '';
if (ragResults.length > 0) {
  context = '=== ОПЫТ КЛАСТЕРИЗАЦИИ ПОХОЖИХ НИШ (RAG) ===\n\n';
  ragResults.forEach((r, i) => {
    const p = r.payload || {};
    context += `Проект ${i+1} (сходство: ${Math.round(r.score*100)}%):\n`;
    context += `  Ниша: ${p.niche||'?'}, город: ${p.city||'?'}\n`;
    context += `  Кластеров: ${p.clusters_count||'?'}, ключей: ${p.total_keywords||'?'}\n`;
    if (p.clusters_summary) {
      const summary = typeof p.clusters_summary === 'string' 
        ? p.clusters_summary.substring(0, 600) 
        : JSON.stringify(p.clusters_summary).substring(0, 600);
      context += `  Структура: ${summary}\n`;
    }
    context += '---\n';
  });
  context += '=== КОНЕЦ RAG КОНТЕКСТА ===';
}

return [{ json: {
  rag_context: context || 'Нет данных из прошлых проектов — первый проект в этой нише.',
  rag_sources: ragResults.length,
  rag_top_score: ragResults[0]?.score || 0,
  rag_avg_score: ragResults.length > 0 ? (ragResults.reduce((s,r) => s + r.score, 0) / ragResults.length).toFixed(3) : 0
}}];

let wordstatResponse = {};
try { wordstatResponse = $('Wordstat API').first().json; } catch(e) {}
const ragInfo = $('Format RAG Context').first().json;
const validate = $('Validate & Sanitize Input').first().json;

const results = Array.isArray(wordstatResponse) ? wordstatResponse : [wordstatResponse];
const keywords = [];
for (const result of results) {
  const topRequests = result.topRequests || result.phrases || [];
  for (const item of topRequests) {
    const phrase = (item.phrase || item.keyword || '').toLowerCase().trim();
    const count = item.count || item.frequency || item.shows || 0;
    if (phrase && phrase.length >= 3 && count >= 5) {
      keywords.push({ keyword: phrase, frequency: count });
    }
  }
}

// Deduplicate
const unique = {};
for (const k of keywords) {
  if (!unique[k.keyword] || unique[k.keyword].frequency < k.frequency) {
    unique[k.keyword] = k;
  }
}

const kwArray = Object.values(unique)
  .sort((a, b) => b.frequency - a.frequency)
  .slice(0, validate.max_keywords);

if (kwArray.length < 5) {
  throw new Error(`Wordstat вернул слишком мало ключей (${kwArray.length}). Проверьте niche/city.`);
}

const kwLines = kwArray.map(k => k.keyword + '|' + k.frequency).join('\n');

const systemPrompt = `Ты Senior SEO-специалист по российскому рынку (Яндекс + Google). Год: 2026.

ЗАДАЧА: кластеризация семантического ядра для сайта.

${ragInfo.rag_context}

ПРАВИЛА КЛАСТЕРИЗАЦИИ:
1. Один кластер = одна посадочная страница (принцип 1:1)
2. Главный ключ кластера = самый частотный и точно описывающий intent страницы
3. Коммерческие кластеры приоритетнее информационных
4. Ключ НЕ может быть в двух кластерах (строгая дедупликация)
5. Минимум 3 ключа в кластере. Максимум 30 кластеров.
6. Для каждого ключа обязательно определи intent_type
7. Для каждого кластера придумай AEO-запрос (как спросят AI-ассистента)
8. recommended_url должен быть ЧПУ на транслите
9. Приоритет кластера: 1 = самый важный для бизнеса
10. Для каждого ключа укажи поле engine: "yandex" | "google" | "both"

МАРКИРОВКА ПОИСКОВЫХ СИСТЕМ:
- "yandex": запросы с городом, «рядом», «рейтинг», «отзывы», разговорные, «недорого»
- "google": англицизмы, «best», «vs», «review», длинные информационные, технические  
- "both": общие коммерческие запросы, универсальные

ТИПЫ КЛАСТЕРОВ:
- commercial: услуги, цены, заказ (максимальный приоритет)
- informational: статьи, гайды, вопросы
- navigation: контакты, о компании, филиалы
- local: гео-запросы с районами/станциями метро/улицами

INTENT ТИПЫ КЛЮЧЕЙ:
- transactional: купить, заказать, цена, стоимость, записаться
- informational: как, что такое, почему, отзывы, сколько
- navigational: бренд, адрес, сайт, телефон
- commercial_investigation: лучший, рейтинг, сравнить, топ, какой выбрать

JSON ФОРМАТ ОТВЕТА (строго без markdown):
{
  "clusters": [
    {
      "cluster_name": "название",
      "main_keyword": "главный ключ",
      "page_type": "commercial",
      "priority": 1,
      "aeo_query": "как спросят AI-ассистента",
      "recommended_url": "/transliterated-url/",
      "keywords": [
        {"keyword": "ключ", "frequency": 100, "intent_type": "transactional", "engine": "both"}
      ]
    }
  ]
}`;

const userPrompt = `Кластеризуй семантическое ядро.\n\nНИША: ${validate.niche}\nГОРОД: ${validate.city}\nВСЕГО КЛЮЧЕЙ: ${kwArray.length}\n\nКЛЮЧЕВЫЕ СЛОВА (keyword|frequency):\n${kwLines}`;

const payload = {
  model: 'llama-3.3-70b-versatile',
  max_tokens: 8000,
  temperature: 0.25,
  top_p: 0.9,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
};

return [{ json: {
  groq_payload: payload,
  keywords_count: kwArray.length,
  keywords_sample: kwArray.slice(0, 10),
  niche: validate.niche,
  city: validate.city,
  project_id: validate.project_id,
  start_time: validate.start_time,
  attempt: validate.attempt || 1
}}];

const inputData = $input.first().json;
if (inputData.error || inputData.code === 'ERR_BAD_REQUEST' || !inputData.choices) {
  return [{ json: {
    clusters: [], clusters_count: 0,
    total_keywords_original: 0, total_keywords_clustered: 0,
    commercial_clusters: 0, informational_clusters: 0, local_clusters: 0,
    aeo_coverage: 0, project_id: '', niche: '', city: '',
    qc_score: 0, issues: ['LLM call failed completely'],
    status: 'failed', groq_tokens: 0, latency_ms: 0,
    rag_sources: 0, timestamp: new Date().toISOString(),
    engine_tagged: 0, engine_total: 0, attempt: 1
  }}];
}

const groqResponse = $input.first().json;
const prevData = $('Build Groq Prompt v4.0').first().json;

// === ROBUST JSON PARSING ===
let rawContent = groqResponse?.choices?.[0]?.message?.content || '';
const tokens = groqResponse?.usage?.total_tokens || 0;

// Clean LLM output
let cleanJson = rawContent
  .replace(/^\xEF\xBB\xBF/, '')          // BOM
  .replace(/```json\s*/gi, '')             // markdown json blocks
  .replace(/```\s*/gi, '')                 // markdown blocks
  .replace(/^[^{\[]*/, '')                 // junk before JSON
  .replace(/[^}\]]*$/, '')                 // junk after JSON
  .replace(/,\s*([}\]])/g, '$1')           // trailing commas
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleanJson);
} catch (err1) {
  // Attempt to extract JSON object
  const match = cleanJson.match(/\{[\s\S]+\}/);
  if (match) {
    try { parsed = JSON.parse(match[0]); }
    catch (err2) {
      // Try fixing common issues
      let fixed = match[0]
        .replace(/(['"])\s*:\s*(['"])/g, '"$2')  
        .replace(/\n/g, '\\n')
        .replace(/\t/g, '\\t');
      try { parsed = JSON.parse(fixed); }
      catch (err3) {
        throw new Error('Groq вернул невалидный JSON после 3 попыток парсинга. Первые 500 символов: ' + rawContent.slice(0, 500));
      }
    }
  } else {
    throw new Error('JSON не найден в ответе Groq. Первые 500 символов: ' + rawContent.slice(0, 500));
  }
}

// === CLUSTER VALIDATION & NORMALIZATION ===
const validPageTypes = ['commercial', 'informational', 'navigation', 'local'];
const validIntents = ['transactional', 'informational', 'navigational', 'commercial_investigation'];

const transliterate = (text) => {
  const map = {'а':'a','б':'b','в':'v','г':'g','д':'d','е':'e','ё':'yo','ж':'zh','з':'z','и':'i','й':'j','к':'k','л':'l','м':'m','н':'n','о':'o','п':'p','р':'r','с':'s','т':'t','у':'u','ф':'f','х':'kh','ц':'ts','ч':'ch','ш':'sh','щ':'shch','ъ':'','ы':'y','ь':'','э':'e','ю':'yu','я':'ya',' ':'-'};
  return text.toLowerCase().split('').map(c => map[c] !== undefined ? map[c] : c).join('').replace(/[^a-z0-9-]/g, '').replace(/-+/g, '-').replace(/^-|-$/g, '');
};

const seenKeywords = new Set();
const clusters = (parsed.clusters || []).map((c, idx) => {
  const keywords = Array.isArray(c.keywords) ? c.keywords
    .map(k => {
      const kw = (typeof k === 'string' ? k : (k.keyword || '')).toLowerCase().trim();
      const freq = typeof k === 'string' ? 0 : (parseInt(k.frequency) || 0);
      const intent = typeof k === 'string' ? 'informational' : (validIntents.includes(k.intent_type) ? k.intent_type : 'informational');
      return { keyword: kw, frequency: freq, intent_type: intent };
    })
    .filter(k => {
      if (!k.keyword || k.keyword.length < 2 || seenKeywords.has(k.keyword)) return false;
      seenKeywords.add(k.keyword);
      return true;
    }) : [];

  const mainKw = c.main_keyword || (keywords[0]?.keyword) || 'Кластер ' + (idx + 1);
  const slug = c.recommended_url || '/' + transliterate(mainKw) + '/';

  return {
    cluster_name: c.cluster_name || 'Кластер ' + (idx + 1),
    main_keyword: mainKw,
    page_type: validPageTypes.includes(c.page_type) ? c.page_type : 'commercial',
    priority: Math.min(Math.max(parseInt(c.priority) || (idx + 1), 1), 30),
    keywords,
    keywords_count: keywords.length,
    total_frequency: keywords.reduce((s, k) => s + k.frequency, 0),
    recommended_url: slug.startsWith('/') ? slug : '/' + slug,
    aeo_query: c.aeo_query || ''
  };
}).filter(c => c.keywords.length >= 1);

// === QC SCORING ===
const totalKw = clusters.reduce((sum, c) => sum + c.keywords_count, 0);
const issues = [];
if (clusters.length === 0) issues.push('0 кластеров');
if (clusters.length > 30) issues.push(`${clusters.length} кластеров (макс 30)`);
if (totalKw < 10) issues.push(`Всего ${totalKw} ключей (мин 10)`);
const commercialClusters = clusters.filter(c => c.page_type === 'commercial').length;
if (commercialClusters === 0) issues.push('Нет коммерческих кластеров');
const aeoCount = clusters.filter(c => c.aeo_query && c.aeo_query.length > 10).length;
if (aeoCount < clusters.length * 0.5) issues.push(`AEO только у ${aeoCount}/${clusters.length} кластеров`);
const duplicateCheck = new Set(clusters.map(c => c.main_keyword));
if (duplicateCheck.size < clusters.length) issues.push('Дублирующиеся main_keyword');

// Check engine tagging
let engineTagged = 0, engineTotal = 0;
clusters.forEach(c => {
  c.keywords.forEach(k => {
    engineTotal++;
    if (k.engine && ['yandex','google','both'].includes(k.engine)) engineTagged++;
  });
});
if (engineTotal > 0 && engineTagged < engineTotal * 0.3) {
  issues.push(`Engine tagging: ${engineTagged}/${engineTotal}`);
}

const qc_score = Math.max(0, 100 - (issues.length * 15));
const latency_ms = Date.now() - (prevData.start_time || Date.now());

return [{ json: {
  clusters, clusters_count: clusters.length,
  total_keywords_original: prevData.keywords_count,
  total_keywords_clustered: totalKw,
  commercial_clusters: commercialClusters,
  informational_clusters: clusters.filter(c => c.page_type === 'informational').length,
  local_clusters: clusters.filter(c => c.page_type === 'local').length,
  aeo_coverage: clusters.length > 0 ? Math.round((aeoCount / clusters.length) * 100) : 0,
  project_id: prevData.project_id, niche: prevData.niche, city: prevData.city,
  qc_score, issues: issues.length > 0 ? issues : null,
  status: qc_score >= 70 ? 'ready' : (qc_score >= 40 ? 'review' : 'failed'),
  groq_tokens: tokens,
  latency_ms,
  rag_sources: $('Format RAG Context').first().json.rag_sources || 0,
  timestamp: new Date().toISOString(),
  engine_tagged: engineTagged,
  engine_total: engineTotal,
  attempt: prevData.attempt || 1
}}];

const data = $('Parse & Validate Clusters v3').first().json;
return [{ json: {
  subject: `⚠️ QC FAILED: ${data.niche} / ${data.city} (score: ${data.qc_score})`,
  body: `Workflow: NN_01_Сбор_СЯ_v3.0_PRO
Project: ${data.project_id}
QC Score: ${data.qc_score}
Issues: ${(data.issues || []).join(', ')}
Clusters: ${data.clusters_count}
Keywords: ${data.total_keywords_clustered}
Timestamp: ${data.timestamp}`,
  error_data: data
}}];

const data = $('Parse & Validate Clusters v3').first().json;

// 4 parallel branches: NocoDB Clusters, Qdrant Summary, Qdrant Intents, LLM Log
return [{ json: { ...data, branch: 'orchestrator' } }];

const data = $input.first().json;
return data.clusters.map(cluster => ({
  json: {
    project_id: data.project_id, niche: data.niche, city: data.city,
    cluster_name: cluster.cluster_name, main_keyword: cluster.main_keyword,
    page_type: cluster.page_type, priority: cluster.priority,
    keywords: JSON.stringify(cluster.keywords),
    keywords_count: cluster.keywords_count, total_frequency: cluster.total_frequency,
    recommended_url: cluster.recommended_url, aeo_query: cluster.aeo_query,
    status: 'active', version: 'v4.0', created: data.timestamp
  }
}));

const data = $input.first().json;
const crypto = require('crypto');

const topClusters = data.clusters.filter(c => c.page_type === 'commercial').slice(0, 10)
  .map(c => `${c.cluster_name}: ${c.main_keyword} (${c.total_frequency} показов/мес)`).join('\n');
const aeoQueries = data.clusters.filter(c => c.aeo_query).slice(0, 5).map(c => c.aeo_query).join('\n');

const nicheText = `Ниша: ${data.niche}\nГород: ${data.city}\nКластеров: ${data.clusters_count}\nВсего ключей: ${data.total_keywords_clustered}\nКоммерческих: ${data.commercial_clusters}\n\nТоп коммерческих кластеров:\n${topClusters}\n\nAEO запросы:\n${aeoQueries}\n\nТоп-20 ключей: ${data.clusters.flatMap(c => c.keywords.map(k => k.keyword)).slice(0, 20).join(', ')}`;

// Deterministic ID based on project + type
const pointId = crypto.createHash('md5')
  .update(`${data.project_id}:semantic_core:${data.niche}:${data.city}`)
  .digest('hex').replace(/(.{8})(.{4})(.{4})(.{4})(.{12})/, '$1-$2-$3-$4-$5');

return [{ json: {
  project_id: data.project_id, niche: data.niche, city: data.city,
  niche_text: nicheText, clusters_count: data.clusters_count,
  total_keywords: data.total_keywords_clustered,
  clusters_summary: JSON.stringify(data.clusters.map(c => ({
    name: c.cluster_name, type: c.page_type, kw: c.main_keyword, freq: c.total_frequency, url: c.recommended_url
  }))),
  point_id: pointId
}}];

const prev = $('Prepare Qdrant Summary').first().json;
const vector = $input.first().json.embedding;
if (!vector || !Array.isArray(vector)) throw new Error('Invalid summary embedding vector');

const payload = {
  points: [{
    id: prev.point_id,
    vector: vector,
    payload: {
      project_id: prev.project_id, niche: prev.niche, city: prev.city,
      type: 'semantic_core_analysis', clusters_count: prev.clusters_count,
      total_keywords: prev.total_keywords, clusters_summary: prev.clusters_summary,
      version: 'v4.0', created_at: new Date().toISOString()
    }
  }]
};
return [{ json: { qdrant_payload: payload }}];

const data = $('Parse & Validate Clusters v3').first().json;
const crypto = require('crypto');

const intents = [];
for (const cluster of data.clusters) {
  for (const kw of cluster.keywords) {
    if (kw.keyword) {
      intents.push({
        query: kw.keyword, intent_type: kw.intent_type,
        content_format: cluster.page_type === 'commercial' ? 'landing' : (cluster.page_type === 'informational' ? 'blog' : 'page'),
        hunt_level: kw.intent_type === 'transactional' ? 5 : (kw.intent_type === 'commercial_investigation' ? 4 : (kw.intent_type === 'navigational' ? 3 : 2)),
        cluster_name: cluster.cluster_name, recommended_url: cluster.recommended_url
      });
    }
  }
}

const intentText = intents.slice(0, 50)
  .map(i => `${i.query} | intent: ${i.intent_type} | format: ${i.content_format} | hunt: ${i.hunt_level} | url: ${i.recommended_url}`)
  .join('\n');

const pointId = crypto.createHash('md5')
  .update(`${data.project_id}:intent_mapping:${data.niche}:${data.city}`)
  .digest('hex').replace(/(.{8})(.{4})(.{4})(.{4})(.{12})/, '$1-$2-$3-$4-$5');

return [{ json: {
  intent_text: intentText || 'no intents',
  intents_count: intents.length,
  intents_breakdown: {
    transactional: intents.filter(i => i.intent_type === 'transactional').length,
    informational: intents.filter(i => i.intent_type === 'informational').length,
    navigational: intents.filter(i => i.intent_type === 'navigational').length,
    commercial_investigation: intents.filter(i => i.intent_type === 'commercial_investigation').length
  },
  niche: data.niche, city: data.city, project_id: data.project_id,
  point_id: pointId
}}];

const prev = $('Prepare Intents Batch').first().json;
const vector = $input.first().json.embedding;
if (!vector || !Array.isArray(vector)) throw new Error('Invalid intents embedding');

const payload = {
  points: [{
    id: prev.point_id,
    vector: vector,
    payload: {
      text: prev.intent_text.substring(0, 5000),
      niche: prev.niche, city: prev.city,
      project_id: prev.project_id, intents_count: prev.intents_count,
      intents_breakdown: prev.intents_breakdown,
      type: 'intent_mapping', version: 'v4.0', created_at: new Date().toISOString()
    }
  }]
};
return [{ json: { qdrant_payload: payload }}];

const data = $('Parse & Validate Clusters v3').first().json;

const logEntry = {
  workflow_name: 'NN_01_Сбор_СЯ_v4.0_PRO',
  workflow_id: 'step_01',
  project_id: data.project_id,
  prompt_version: 'v4.0',
  prompt_type: 'keyword_clustering',
  input_data: JSON.stringify({
    niche: data.niche, city: data.city,
    keywords_original: data.total_keywords_original,
    keywords_clustered: data.total_keywords_clustered
  }),
  response_summary: JSON.stringify({
    clusters: data.clusters_count,
    commercial: data.commercial_clusters,
    aeo_coverage: data.aeo_coverage + '%'
  }),
  total_tokens: data.groq_tokens,
  latency_ms: data.latency_ms,
  qc_score: data.qc_score,
  status: data.status,
  issues: data.issues ? JSON.stringify(data.issues) : null,
  created_at: data.timestamp
};

return [{ json: { llm_log_payload: logEntry }}];

const mlInput = $('Prepare ML Features').first().json;
let mlResult = {};
try { mlResult = $input.first().json || {}; } catch(e) {}

return [{ json: {
  ...mlInput,
  ml_aeo_score: mlResult.score ?? null,
  ml_aeo_label: mlResult.label ?? null,
  ml_confidence: mlResult.confidence ?? null,
  ml_available: mlResult.score != null
}}];

const data = $('Parse & Validate Clusters v3').first().json;
const ragInfo = $('Format RAG Context').first().json;

let qdrantOk = false, intentsOk = false, nocodbOk = false, mlData = {};
try { const q = $('Save to Qdrant (Upsert)').first().json; qdrantOk = q.status === 'ok' || q.result?.status === 'acknowledged'; } catch(e) {}
try { const i = $('Save Intents to Qdrant').first().json; intentsOk = i.status === 'ok' || i.result?.status === 'acknowledged'; } catch(e) {}
try { const n = $('NocoDB Save Clusters').first().json; nocodbOk = n.Id != null || n.id != null; } catch(e) {}
try { mlData = $('Merge ML Result').first().json; } catch(e) {}

return [{ json: {
  status: 'success',
  project_id: data.project_id, niche: data.niche, city: data.city,
  clusters_count: data.clusters_count,
  keywords_original: data.total_keywords_original,
  keywords_clustered: data.total_keywords_clustered,
  commercial_clusters: data.commercial_clusters,
  aeo_coverage: data.aeo_coverage + '%',
  qc_score: data.qc_score,
  validation_status: data.status,
  issues: data.issues,
  groq_tokens: data.groq_tokens,
  attempt: data.attempt || 1,
  engine_tagging: {
    tagged: data.engine_tagged || 0,
    total: data.engine_total || 0
  },
  rag_sources: ragInfo.rag_sources,
  rag_top_score: ragInfo.rag_top_score,
  saves: {
    qdrant_summary: qdrantOk,
    qdrant_intents: intentsOk,
    nocodb_clusters: nocodbOk
  },
  ml: {
    aeo_score: mlData.ml_aeo_score ?? null,
    aeo_label: mlData.ml_aeo_label ?? null,
    confidence: mlData.ml_confidence ?? null,
    available: mlData.ml_available ?? false
  },
  latency_ms: data.latency_ms,
  version: 'v4.0_pro',
  timestamp: new Date().toISOString()
}}];

const data = $('Parse & Validate Clusters v3').first().json;
const validate = $('Validate & Sanitize Input').first().json;

return [{ json: {
  ...validate,
  attempt: (data.attempt || 1) + 1,
  retry_reason: `QC ${data.qc_score}/100, issues: ${(data.issues||[]).join(', ')}`
